// src/pages/Tasks.jsx
// Shows all tasks for a project

import { useState, useEffect } from 'react';
import { useParams } from 'react-router-dom';
import API from '../api/axios';
import { useAuth } from '../context/AuthContext';

const statusColors = {
  'todo': '#fef3c7',
  'in-progress': '#dbeafe',
  'done': '#dcfce7',
};

const Tasks = () => {
  const { id: projectId } = useParams(); // Get project ID from URL
  const [tasks, setTasks] = useState([]);
  const [form, setForm] = useState({ title: '', description: '', dueDate: '', priority: 'medium' });
  const [error, setError] = useState('');
  const { user } = useAuth();

  useEffect(() => {
    fetchTasks();
  }, []);

  const fetchTasks = async () => {
    try {
      const { data } = await API.get(`/tasks?project=${projectId}`);
      setTasks(data.tasks);
    } catch (err) {
      setError('Failed to load tasks');
    }
  };

  const handleCreate = async () => {
    if (!form.title) return setError('Task title is required');
    try {
      await API.post('/tasks', { ...form, project: projectId });
      setForm({ title: '', description: '', dueDate: '', priority: 'medium' });
      fetchTasks();
    } catch (err) {
      setError(err.response?.data?.message || 'Failed to create task');
    }
  };

  const handleStatusChange = async (taskId, newStatus) => {
    try {
      await API.put(`/tasks/${taskId}`, { status: newStatus });
      fetchTasks();
    } catch (err) {
      setError('Failed to update task');
    }
  };

  return (
    <div style={styles.container}>
      <h2>✅ Tasks</h2>

      {/* Admin only: Create task form */}
      {user?.role === 'admin' && (
        <div style={styles.form}>
          <h3>Add New Task</h3>
          {error && <div style={styles.error}>{error}</div>}
          <input style={styles.input} placeholder="Task Title"
            value={form.title} onChange={(e) => setForm({ ...form, title: e.target.value })} />
          <input style={styles.input} placeholder="Description"
            value={form.description} onChange={(e) => setForm({ ...form, description: e.target.value })} />
          <input style={styles.input} type="date"
            value={form.dueDate} onChange={(e) => setForm({ ...form, dueDate: e.target.value })} />
          <select style={styles.input} value={form.priority}
            onChange={(e) => setForm({ ...form, priority: e.target.value })}>
            <option value="low">Low Priority</option>
            <option value="medium">Medium Priority</option>
            <option value="high">High Priority</option>
          </select>
          <button style={styles.button} onClick={handleCreate}>+ Add Task</button>
        </div>
      )}

      {/* Task list */}
      <div style={styles.list}>
        {tasks.map((task) => (
          <div key={task._id} style={{
            ...styles.card,
            backgroundColor: statusColors[task.status] || 'white'
          }}>
            <div style={styles.cardHeader}>
              <h3 style={styles.cardTitle}>{task.title}</h3>
              <span style={styles.priority}>{task.priority}</span>
            </div>
            <p style={styles.desc}>{task.description}</p>
            {task.dueDate && (
              <p style={styles.due}>
                📅 Due: {new Date(task.dueDate).toLocaleDateString()}
              </p>
            )}
            {task.assignedTo && (
              <p style={styles.assigned}>👤 {task.assignedTo.name}</p>
            )}

            {/* Status dropdown — everyone can update */}
            <select
              style={styles.select}
              value={task.status}
              onChange={(e) => handleStatusChange(task._id, e.target.value)}
            >
              <option value="todo">To Do</option>
              <option value="in-progress">In Progress</option>
              <option value="done">Done</option>
            </select>
          </div>
        ))}
      </div>

      {tasks.length === 0 && (
        <p style={{ color: '#94a3b8' }}>No tasks yet. Add one above!</p>
      )}
    </div>
  );
};

const styles = {
  container: { maxWidth: '900px', margin: '0 auto' },
  form: {
    background: 'white', padding: '24px', borderRadius: '12px',
    boxShadow: '0 2px 10px rgba(0,0,0,0.08)', marginBottom: '24px',
    display: 'flex', flexDirection: 'column', gap: '12px',
  },
  input: { padding: '10px', border: '1px solid #e2e8f0', borderRadius: '8px', fontSize: '14px' },
  button: { backgroundColor: '#3b82f6', color: 'white', border: 'none', padding: '10px', borderRadius: '8px', cursor: 'pointer' },
  error: { background: '#fee2e2', color: '#dc2626', padding: '10px', borderRadius: '6px' },
  list: { display: 'flex', flexDirection: 'column', gap: '12px' },
  card: { padding: '20px', borderRadius: '12px', boxShadow: '0 2px 8px rgba(0,0,0,0.06)', border: '1px solid #f1f5f9' },
  cardHeader: { display: 'flex', justifyContent: 'space-between', alignItems: 'center' },
  cardTitle: { margin: 0, color: '#1e293b' },
  priority: { background: '#f1f5f9', padding: '2px 10px', borderRadius: '20px', fontSize: '12px' },
  desc: { color: '#64748b', fontSize: '14px', margin: '8px 0' },
  due: { color: '#f59e0b', fontSize: '13px', margin: '4px 0' },
  assigned: { color: '#64748b', fontSize: '13px', margin: '4px 0' },
  select: { padding: '6px', border: '1px solid #e2e8f0', borderRadius: '6px', marginTop: '8px' },
};

export default Tasks;
